// Hand-maintained — NOT regenerated by sync-from-host.mjs.
//
// Known LVIS marketplace signing public keys (ed25519, base64 raw 32B).
//
// The marketplace server signs every artifact with every configured private
// key (see server S4a dual-sign window). A downloaded signature envelope
// carries one entry per key. A client should treat the envelope as valid if
// AT LEAST ONE signature verifies against any public key listed here.
//
// Rotation policy:
//   - Adding a new key is additive — existing artifacts keep verifying via
//     their old signatures, and new artifacts will gain the new signature
//     once the server is redeployed with the corresponding private key.
//   - Removing a key (retirement / S4b) is a breaking change for clients
//     that only trust the removed key. Ship the removal in a new major SDK
//     version and coordinate with release telemetry before executing on
//     the server side.

/**
 * Known marketplace signing public keys, keyed by `key_id`.
 * Values are base64-encoded raw 32-byte ed25519 public keys.
 */
export const MARKETPLACE_PUBLIC_KEYS: Readonly<Record<string, string>> = Object.freeze({
  "dev-v1": "gDzzn5UcdQTwFIxXkXdhZU4k85eUyyyFKfd+fvooDhM=",
  "poc-v1": "Qm3FUAMek2r5OkXCurgX6dNYSqiT1GRnjb5fWfuOoao=",
});

/**
 * Non-production signing keys retained only for local/dev transition workflows.
 * Runtime consumers should exclude them unless they explicitly opt in.
 */
export const MARKETPLACE_TEST_KEY_IDS = Object.freeze(["dev-v1", "poc-v1"] as const);

const TEST_KEY_ID_SET = new Set<string>(MARKETPLACE_TEST_KEY_IDS);

const PROD_MARKETPLACE_PUBLIC_KEYS: Readonly<Record<string, string>> = Object.freeze(
  Object.fromEntries(
    Object.entries(MARKETPLACE_PUBLIC_KEYS).filter(([keyId]) => !TEST_KEY_ID_SET.has(keyId)),
  ),
);

export function getTrustedMarketplacePublicKeys(
  options?: { includeTestKeys?: boolean },
): Readonly<Record<string, string>> {
  return options?.includeTestKeys ? MARKETPLACE_PUBLIC_KEYS : PROD_MARKETPLACE_PUBLIC_KEYS;
}

/**
 * Canonical key_id of the current POC signing key. This is NOT a real
 * production key — the marketplace server refuses to boot with it loaded
 * when `LVIS_ENV=production`. A future SDK major will rotate this to the
 * real prod key once provisioned.
 */
export const MARKETPLACE_PRIMARY_KEY_ID = "poc-v1" as const;
